interface JsonRpcErrorObject {
  error: {
    code: number;
    data?: unknown;
    message: string;
  };
  id: null | number | string;
  jsonrpc: string;
}

export class JsonRpcError extends Error {
  public error: {
    code: number;
    data?: unknown;
    message: string;
  };

  public id: null | number | string | undefined;

  public jsonrpc: string;

  public status: number;

  /**
   * @param code A Number that indicates the error type that occurred. This MUST be an integer.
   * @param status The HTTP status code generated by the origin server for this occurrence of the problem.
   * @param message A String providing a short description of the error. The message SHOULD be limited to a concise single sentence.
   * @param id It MUST be the same as the value of the id member in the Request Object. If there was an error in detecting the id in the Request object (e.g. Parse error/Invalid Request), it MUST be Null.
   * @param data A Primitive or Structured value that contains additional information about the error. This may be omitted.
   */
  constructor(
    code: number,
    status: number,
    message: string,
    id?: null | number | string,
    data?: unknown,
  ) {
    super(message);
    this.name = "JsonRpcError";
    this.jsonrpc = "2.0";
    this.status = status;
    this.error = { code, data, message };
    this.id = id;
  }

  toJSON(): JsonRpcErrorObject {
    return {
      error: this.error,
      // eslint-disable-next-line unicorn/no-null
      id: this.id ?? null,
      jsonrpc: this.jsonrpc,
    };
  }

  override toString(): string {
    return `${this.error.code} - ${this.error.message}`;
  }
}
